def binarySearch (arr : Array Nat) (value : Nat) (low : Nat) (high : Nat) : Nat :=
  if low > high then high + 1
  else let mid := low + ((high - low) / 2);
       if arr[mid] < value then binarySearch arr value (mid + 1) high
       else binarySearch arr value low mid

def gallopRight (key : Nat) (arr : Array Nat) (base : Nat) (length : Nat) (hint : Nat) : Nat :=
  let mut lastOffset := 1;
  let mut k := 0;
  while k < length && hint + lastOffset < arr.size && arr[hint + lastOffset] < key do
    let offset := 2 * lastOffset;
    if offset <= k then
      k := binarySearch arr key (hint + k + 1) (hint + offset - 1);
      return min (hint + k) (arr.size - 1)
    else
      lastOffset := offset;
      k := k + lastOffset
  return hint + lastOffset

def insertionSort (arr : Array Nat) (left : Nat) (right : Nat) : Unit :=
  for i := left + 1; i <= right; i := i + 1 do
    let mut j := i;
    while j > left && arr[j - 1] > arr[j] do
      arr.swap j (j - 1);
      j := j - 1

def mergeLo (arr : Array Nat) (lo : Nat) (mid : Nat) (hi : Nat) : Unit :=
  let mut t := Array.map (fun i => arr[i]) (lo..=hi);
  let mut i := lo;
  let mut j := mid + 1;
  for k in lo..=hi do
    if i > mid then
      arr[k] := t[j - lo];
      j := j + 1
    else if j > hi then
      arr[k] := t[i - lo];
      i := i + 1
    else if t[i - lo] < t[j - lo] then
      arr[k] := t[i - lo];
      i := i + 1
    else
      arr[k] := t[j - lo];
      j := j + 1

def mergeHi (arr : Array Nat) (lo : Nat) (mid : Nat) (hi : Nat) : Unit :=
  let mut t := Array.map (fun i => arr[i]) (lo..=hi);
  let mut i := mid;
  let mut j := hi;
  for k in lo..=hi reversed do
    if i < lo then
      arr[k] := t[j - lo];
      j := j - 1
    else if j < mid then
      arr[k] := t[i - lo];
      i := i + 1
    else if t[i - lo] < t[j - lo] then
      arr[k] := t[i - lo];
      i := i + 1
    else
      arr[k] := t[j - lo];
      j := j - 1

def mergeAt (arr : Array Nat) (lo : Nat) (mid : Nat) (hi : Nat) : Unit :=
  if mid < lo + (hi - lo) / 2 then
    mergeLo arr lo mid hi
  else
    mergeHi arr lo mid hi

def timSort (arr : Array Nat) : Unit :=
  let minRun := if arr.size < 64 then arr.size else Nat.floorDiv (arr.size, 6) * 2;
  let mut i := 0;
  while i < arr.size do
    let mut runLength := 0;
    let descending := arr[i + 1] < arr[i];
